sealed class ClaudeStreamEvent {
    /** A text delta from content_block_delta SSE events. */
    data class Token(val text: String) : ClaudeStreamEvent()

    /** Stream completed cleanly (message_stop received). */
    object StreamEnd : ClaudeStreamEvent()

    /** Network error, HTTP error, or JSON parse failure. */
    data class Error(val message: String) : ClaudeStreamEvent()
}

class ChatViewModel(private val repository: ClaudeRepository) : ViewModel() {

    private val _uiState = MutableStateFlow(ChatUiState())
    val uiState: StateFlow<ChatUiState> = _uiState.asStateFlow()

    private var streamJob: Job? = null

    fun sendMessage(userText: String) {
        if (userText.isBlank() || _uiState.value.isStreaming) return

        streamJob = viewModelScope.launch {
            _uiState.update {
                it.copy(
                    messages = it.messages + ChatMessage("user", userText),
                    streamingText = "",
                    isStreaming = true,
                    error = null
                )
            }

            repository.streamMessage(userText).collect { event ->
                when (event) {
                    is ClaudeStreamEvent.Token ->
                        _uiState.update { it.copy(streamingText = it.streamingText + event.text) }

                    is ClaudeStreamEvent.StreamEnd -> {
                        val completed = _uiState.value.streamingText
                        _uiState.update {
                            it.copy(
                                messages = it.messages + ChatMessage("assistant", completed),
                                streamingText = "",
                                isStreaming = false
                            )
                        }
                    }

                    is ClaudeStreamEvent.Error ->
                        _uiState.update {
                            it.copy(
                                streamingText = "",
                                isStreaming = false,
                                error = event.message
                            )
                        }
                }
            }
        }
    }

    fun cancelStream() {
        streamJob?.cancel()
        _uiState.update { it.copy(isStreaming = false, streamingText = "") }
    }
}

repository.streamMessage(text)
    .onEach { event ->
        if (event is ClaudeStreamEvent.Token) {
            analytics.logTokenReceived(sessionId, event.text.length)
        }
    }
    .collect { event -> /* normal when(event) handling */ }

val accumulatedText: Flow<String> = repository.streamMessage(text)
    .filterIsInstance<ClaudeStreamEvent.Token>()
    .map { it.text }
    .scan("") { acc, delta -> acc + delta }

// The Flow emits "", "H", "He", "Hel", "Hell", "Hello", … on each token
// Useful for injecting into a composable via collectAsStateWithLifecycle()

repository.streamMessage(text)
    .catch { throwable ->
        // .catch must call emit() to forward an event, or re-throw, or just
        // update state directly (the coroutine context is still accessible)
        _uiState.update {
            it.copy(
                isStreaming = false,
                error = throwable.message ?: "Unknown error"
            )
        }
        // NOT emitting here ends the flow normally after the catch block
    }
    .onCompletion {
        // always runs — cancellation, normal end, or caught exception
        _uiState.update { it.copy(isStreaming = false) }
    }
    .collect { event -> when(event) { /* … */ } }

streamJob = viewModelScope.launch {
    _uiState.update { it.copy(isStreaming = true, error = null) }

    repository.streamMessage(userText)
        .catch { throwable ->
            _uiState.update { it.copy(error = throwable.localizedMessage) }
        }
        .onCompletion {
            // Runs even on cancellation — safely resets the flag
            _uiState.update { it.copy(isStreaming = false) }
        }
        .collect { event ->
            when (event) {
                is ClaudeStreamEvent.Token ->
                    _uiState.update { it.copy(streamingText = it.streamingText + event.text) }
                is ClaudeStreamEvent.StreamEnd -> {
                    val done = _uiState.value.streamingText
                    _uiState.update {
                        it.copy(
                            messages = it.messages + ChatMessage("assistant", done),
                            streamingText = ""
                        )
                    }
                }
                is ClaudeStreamEvent.Error ->
                    _uiState.update { it.copy(error = event.message, streamingText = "") }
            }
        }
}

// ViewModel exposes hot StateFlow — multiple collectors, one network request
val uiState: StateFlow<ChatUiState> = _uiState.asStateFlow()

// Alternatively, convert the cold Flow to a hot SharedFlow with replay
private val sharedStream: SharedFlow<ClaudeStreamEvent> =
    repository.streamMessage(text)
        .shareIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5_000),
            replay = 0
        )

