class ChatViewModelTest {

    private val repository = FakeClaudeRepository()
    private val viewModel = ChatViewModel(repository)

    @Test
    fun `tokens accumulate and StreamEnd finalizes message`() = runTest {
        repository.queueEvents(
            ClaudeStreamEvent.Token("Hello"),
            ClaudeStreamEvent.Token(", world"),
            ClaudeStreamEvent.StreamEnd
        )

        viewModel.uiState.test {
            // initial emission from StateFlow
            val initial = awaitItem()
            assertFalse(initial.isStreaming)

            viewModel.sendMessage("Hi")

            // isStreaming = true, user message added
            val streaming = awaitItem()
            assertTrue(streaming.isStreaming)
            assertEquals(1, streaming.messages.size)
            assertEquals("", streaming.streamingText)

            // first Token
            val afterFirst = awaitItem()
            assertEquals("Hello", afterFirst.streamingText)

            // second Token
            val afterSecond = awaitItem()
            assertEquals("Hello, world", afterSecond.streamingText)

            // StreamEnd — message committed
            val done = awaitItem()
            assertFalse(done.isStreaming)
            assertEquals("", done.streamingText)
            assertEquals(2, done.messages.size)
            assertEquals("Hello, world", done.messages.last().text)

            cancelAndIgnoreRemainingEvents()
        }
    }

    @Test
    fun `Error event sets error and stops streaming`() = runTest {
        repository.queueEvents(
            ClaudeStreamEvent.Error("rate limit exceeded")
        )

        viewModel.uiState.test {
            awaitItem() // initial
            viewModel.sendMessage("Hi")
            awaitItem() // isStreaming = true

            val errorState = awaitItem()
            assertFalse(errorState.isStreaming)
            assertEquals("rate limit exceeded", errorState.error)
            cancelAndIgnoreRemainingEvents()
        }
    }
}

class FakeClaudeRepository : ClaudeRepository {
    private val events = mutableListOf<ClaudeStreamEvent>()

    fun queueEvents(vararg e: ClaudeStreamEvent) {
        events.clear()
        events.addAll(e)
    }

    override fun streamMessage(text: String): Flow<ClaudeStreamEvent> = flow {
        events.forEach { emit(it) }
    }
}
